svg.script:
(function () {
  var svg = document.documentElement;
  var CX = 560, CY = 140, QA = -20;
  var kv = document.getElementById('kv'), ks = document.getElementById('ks');
  var bar = document.getElementById('bar'), arc = document.getElementById('arc');
  var th = document.getElementById('th'), rv = document.getElementById('rv');
  var klab = document.getElementById('klab'), ov = document.getElementById('ov');
  function pt(a, r) {
    var t = a * Math.PI / 180;
    return [CX + r * Math.sin(t), CY - r * Math.cos(t)];
  }
  function upd(a) {
    a = Math.round(a);
    var d = a - QA;
    while (d > 180) d -= 360;
    while (d < -180) d += 360;
    var deg = Math.abs(d);
    kv.setAttribute('transform', 'rotate(' + a + ')');
    ks.setAttribute('transform', 'rotate(' + a + ')');
    var kp = pt(a, 74);
    klab.setAttribute('x', kp[0].toFixed(1));
    klab.setAttribute('y', (kp[1] + 4).toFixed(1));
    var p1 = pt(QA, 26), p2 = pt(a, 26);
    arc.setAttribute('d', 'M' + p1[0].toFixed(1) + ' ' + p1[1].toFixed(1) +
      ' A26 26 0 0 ' + (d > 0 ? 1 : 0) + ' ' + p2[0].toFixed(1) + ' ' + p2[1].toFixed(1));
    var mid = pt(QA + d / 2, 40);
    th.setAttribute('x', mid[0].toFixed(1));
    th.setAttribute('y', (mid[1] + 4).toFixed(1));
    th.setAttribute('opacity', deg < 12 ? 0 : 1);
    var c = Math.cos(deg * Math.PI / 180);
    if (c >= 0) { bar.setAttribute('x', CX); bar.setAttribute('width', c * 120); }
    else { bar.setAttribute('x', CX + c * 120); bar.setAttribute('width', -c * 120); }
    rv.textContent = 'angle θ = ' + deg + '° → cos θ = ' + (c < 0 ? '−' : '') + Math.abs(c).toFixed(2);
  }
  function updFrom(e) {
    var p = svg.createSVGPoint();
    p.x = e.clientX; p.y = e.clientY;
    var q = p.matrixTransform(svg.getScreenCTM().inverse());
    upd(Math.atan2(q.x - CX, CY - q.y) * 180 / Math.PI);
  }
  var drag = false;
  ov.addEventListener('pointerdown', function (e) { drag = true; ov.setPointerCapture(e.pointerId); updFrom(e); });
  ov.addEventListener('pointermove', function (e) { if (drag || e.pointerType === 'mouse') updFrom(e); });
  addEventListener('pointerup', function () { drag = false; });
  upd(45);
})();
